-- Transaction-scoped advisory lock with a 1-second timeout
CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint)
RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
  deadline timestamptz := clock_timestamp() + interval '1 second';
BEGIN
  LOOP
    IF pg_try_advisory_xact_lock(key) THEN
      RETURN true;
    END IF;

    IF clock_timestamp() >= deadline THEN
      RETURN false;
    END IF;

    PERFORM pg_sleep(0.01); -- 10ms backoff to avoid busy-waiting
  END LOOP;
END;
$$;

