-- Enforce "each account must have at least one disp" with deferrable constraint triggers

-- 1) At commit time, ensure every newly inserted/updated account has at least one disp
CREATE OR REPLACE FUNCTION enforce_account_has_disp() RETURNS trigger
LANGUAGE plpgsql AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM disp d
    WHERE d.account_id = NEW.account_id
  ) THEN
    RAISE EXCEPTION 'Account % must have at least one associated disp', NEW.account_id;
  END IF;
  RETURN NULL;
END;
$$;

CREATE CONSTRAINT TRIGGER account_must_have_disp
AFTER INSERT OR UPDATE ON account
DEFERRABLE INITIALLY DEFERRED
FOR EACH ROW
EXECUTE FUNCTION enforce_account_has_disp();

-- 2) Prevent deleting or reassigning the last disp of an existing account
CREATE OR REPLACE FUNCTION prevent_orphan_accounts_on_disp() RETURNS trigger
LANGUAGE plpgsql AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    -- Allow cascade delete when the parent account is being deleted;
    -- otherwise, forbid removing the last disp.
    IF EXISTS (SELECT 1 FROM account a WHERE a.account_id = OLD.account_id) THEN
      IF NOT EXISTS (
        SELECT 1
        FROM disp d
        WHERE d.account_id = OLD.account_id
          AND d.disp_id <> OLD.disp_id
      ) THEN
        RAISE EXCEPTION 'Cannot delete last disp for account %', OLD.account_id;
      END IF;
    END IF;
    RETURN NULL;
  ELSIF TG_OP = 'UPDATE' THEN
    -- If moving this disp to a different account, ensure the old account keeps at least one disp
    IF OLD.account_id IS DISTINCT FROM NEW.account_id THEN
      IF EXISTS (SELECT 1 FROM account a WHERE a.account_id = OLD.account_id) THEN
        IF NOT EXISTS (
          SELECT 1
          FROM disp d
          WHERE d.account_id = OLD.account_id
            AND d.disp_id <> OLD.disp_id
        ) THEN
          RAISE EXCEPTION 'Update would remove last disp for account %', OLD.account_id;
        END IF;
      END IF;
    END IF;
    RETURN NULL;
  END IF;
  RETURN NULL;
END;
$$;

CREATE CONSTRAINT TRIGGER disp_keep_at_least_one
AFTER DELETE OR UPDATE OF account_id ON disp
DEFERRABLE INITIALLY DEFERRED
FOR EACH ROW
EXECUTE FUNCTION prevent_orphan_accounts_on_disp();

