-- Fixed version of your first procedure (uses explicit column list and avoids variable/keyword collisions)
CREATE OR REPLACE PROCEDURE do_while()
LANGUAGE plpgsql
AS $$
DECLARE
    v_i       INT := 1;
    v_start   INT := 120;
    v_counter INT := 1;
    v_end     INT := 300;
BEGIN
    WHILE v_i <= v_end LOOP
        INSERT INTO table1 ("start", "counter", difference, "end")
        VALUES (v_start, v_counter, v_start + v_counter, v_end);

        v_i := v_i + 1;
        v_counter := v_counter + 1;
    END LOOP;
END;
$$;

-- Corrected procedure that:
-- 1) gets the current row count
-- 2) gets the "next starting id" as MAX(id)+1 (COALESCE to handle empty table)
-- 3) inserts exactly that many rows using those values
CREATE OR REPLACE PROCEDURE insert_more()
LANGUAGE plpgsql
AS $$
DECLARE
    v_total_rows INT;     -- how many rows currently in the table
    v_start_val  INT;     -- value to store in "start" column (MAX(id)+1 or 1 if empty)
    v_counter    INT := 1;
BEGIN
    SELECT COUNT(*) INTO v_total_rows FROM table1;
    SELECT COALESCE(MAX(id) + 1, 1) INTO v_start_val FROM table1;

    WHILE v_counter <= v_total_rows LOOP
        INSERT INTO table1 ("start", "counter", difference, "end")
        VALUES (v_start_val, v_counter, v_start_val + v_counter, v_total_rows);

        v_counter := v_counter + 1;
    END LOOP;
END;
$$;

