CREATE OR REPLACE FUNCTION find_test_table_column(
    in_column1 varchar,
    in_column2 varchar,
    in_column3 varchar,
    in_column4 varchar,
    in_requested_column varchar
) RETURNS varchar
LANGUAGE plpgsql
STABLE
AS $$
DECLARE
    result varchar;
    target_col text;
BEGIN
    -- Normalize and validate which column to return
    target_col := lower(trim(in_requested_column));
    IF target_col NOT IN ('column1', 'column2', 'column3', 'column4') THEN
        RAISE EXCEPTION 'Invalid requested column: % (allowed: COLUMN1, COLUMN2, COLUMN3, COLUMN4)', in_requested_column;
    END IF;

    -- Get the first matching row (by created_at) and return the requested column
    EXECUTE format(
        'SELECT %I
           FROM test_table
          WHERE column1 = $1
            AND column2 = $2
            AND column3 = $3
            AND ($4 IS NULL OR column4 = $4)
          ORDER BY created_at ASC
          LIMIT 1',
        target_col
    )
    INTO result
    USING in_column1, in_column2, in_column3, in_column4;

    RETURN result;
END;
$$;

