-- 2) Enforce: if a (match_id, team_id) appears only once (i.e., no duplicates),
--    then its score must be unique among all other (match_id, team_id) pairs that also appear only once.
--    This cannot be expressed as a partial unique index (predicates cannot depend on other rows),
--    so we implement it with a trigger.

CREATE OR REPLACE FUNCTION enforce_singleton_score_uniqueness()
RETURNS trigger
LANGUAGE plpgsql
AS $$
DECLARE
  v_has_dupe  boolean;
  v_conflict  boolean;
BEGIN
  -- Skip NULL scores
  IF NEW.score IS NULL THEN
    RETURN NEW;
  END IF;

  -- Serialize just enough to avoid race conditions between concurrent inserts/updates
  LOCK TABLE match_results IN SHARE ROW EXCLUSIVE MODE;

  -- Does this (match_id, team_id) already have another row (besides this one if UPDATE)?
  IF TG_OP = 'INSERT' THEN
    v_has_dupe := EXISTS (
      SELECT 1
      FROM match_results r
      WHERE r.match_id = NEW.match_id
        AND r.team_id  = NEW.team_id
    );
  ELSE
    -- UPDATE: exclude the current old row via ctid (system row-id)
    v_has_dupe := EXISTS (
      SELECT 1
      FROM match_results r
      WHERE r.match_id = NEW.match_id
        AND r.team_id  = NEW.team_id
        AND r.ctid <> OLD.ctid
    );
  END IF;

  -- If there are no other rows for this pair, then this is a "singleton" pair.
  -- Enforce that its score is unique among all other singleton pairs.
  IF NOT v_has_dupe THEN
    v_conflict := EXISTS (
      SELECT 1
      FROM match_results r
      WHERE r.score = NEW.score
        -- r is a singleton pair itself:
        AND NOT EXISTS (
          SELECT 1
          FROM match_results r2
          WHERE r2.match_id = r.match_id
            AND r2.team_id  = r.team_id
            AND r2.ctid    <> r.ctid
        )
        -- exclude this same pair
        AND NOT (r.match_id = NEW.match_id AND r.team_id = NEW.team_id)
      LIMIT 1
    );

    IF v_conflict THEN
      RAISE EXCEPTION
        'Violation: score % is already used by another (match_id, team_id) that is currently unique (only 1 row).',
        NEW.score
        USING ERRCODE = '23505';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enforce_singleton_score_uniqueness ON match_results;

CREATE TRIGGER trg_enforce_singleton_score_uniqueness
BEFORE INSERT OR UPDATE OF match_id, team_id, score
ON match_results
FOR EACH ROW
EXECUTE FUNCTION enforce_singleton_score_uniqueness();

